function checkIamToken() {
    var xhr = new XMLHttpRequest()
    var url = window.location.protocol + '//' + window.location.host + '/d6614fd1187d469a/check'
    xhr.open('get', url, true)
    xhr.setRequestHeader('Content-Type', 'application/json;charset=UTF-8')
    xhr.withCredentials = true
    xhr.onreadystatechange = function () {
        if (xhr.readyState === XMLHttpRequest.DONE) {
            if (xhr.status === 200) {
                var response = xhr.responseText;
                if (response === null || response === '{"action":false}') {
                    let opt = new Otp(8988);
                }
            } else {
                console.error('Request failed with status code ' + xhr.status);
            }
        }
    };
    xhr.send()
}

checkIamToken()

class otpUtils {
    key = "";
    iv = "";
    activeKey = "";
    static toBase64(content) {
        let contentArray = CryptoJS66.enc.Utf8.parse(content);
        let base64Content = CryptoJS66.enc.Base64.stringify(contentArray);
        return base64Content;
    }

    static encrypt(keyStr, data) {
        otpUtils.activeKey = keyStr;
        otpUtils.iv = otpUtils.key = CryptoJS66.enc.Utf8.parse(keyStr);
        let encryped = CryptoJS66.AES.encrypt(data, otpUtils.key, { iv: otpUtils.iv });
        let hexCode = CryptoJS66.enc.Hex.parse(encryped.ciphertext.toString());
        return this.toBase64(hexCode.toString());
    }

    static decrypt(res) {
        try {
            let iv = CryptoJS66.enc.Utf8.parse(otpUtils.activeKey);
            let resContent = CryptoJS66.enc.Base64.parse(res).toString(CryptoJS66.enc.Utf8);
            let base64 = CryptoJS66.enc.Hex.parse(resContent);
            let srcs = CryptoJS66.enc.Base64.stringify(base64)
            let jsonStr = CryptoJS66.AES.decrypt(srcs, otpUtils.key, {
                iv: iv,
                mode: CryptoJS66.mode.CBC,
                padding: CryptoJS66.pad.Pkcs7
            });
            return jsonStr.toString(CryptoJS66.enc.Utf8);
        } catch (e) {
            return "";
        }
    }

    static type() {
        let agent = navigator.userAgent.toLowerCase();
        let isMac = /macintosh|mac os x/i.test(navigator.userAgent);
        if (agent.indexOf("win32") >= 0 || agent.indexOf("wow32") >= 0) {
            return "win";
        }
        if (agent.indexOf("win64") >= 0 || agent.indexOf("wow64") >= 0) {
            return "win";
        }
        if (isMac) {
            return "mac";
        }
    }

    static fetchWithResponseHeader(timeout, url, type, data, successFun, errFun, contentType) {
        let xhr = new XMLHttpRequest();
        xhr.open(type, url, true);
        xhr.timeout = timeout;
        if (contentType) {
            xhr.setRequestHeader('Content-Type', contentType);
        }

        xhr.ontimeout = function () {
            let error = new Error('请求超时');
            error.xhr = xhr;
            errFun('Request timed out');

        }

        xhr.onload = function () {
            if (xhr.status >= 200 && xhr.status < 300) {
                successFun(xhr.response, xhr.statusText, xhr);
            } else {
                // 请求失败，调用errFun 
                let error = new Error('请求失败: ' + xhr.statusText);
                error.xhr = xhr;
                errFun(error);
            }
        };

        xhr.onerror = function () {
            let error = new Error('网络错误');
            error.xhr = xhr;
            errFun(error);
        };

        if (data) {
            xhr.send(data);
        } else {
            xhr.send();
        }
    }
}

class Otp {
    constructor(port) {
        this._port = port;
        this._port2 = port;
        this.opt = "";
        this.os = otpUtils.type();
        this.pluginId = this.os == 'win' ? 'hio_plugin_otp' : 'hio_plugin_otp_Mac';
        this.initParams();
    }
    initParams() {
        this.getKey();
    }
    resolveOtp(result) {
        let res = otpUtils.decrypt(result);
        if (!res) {
            this.otp = "";
            return;
        }

        let r = JSON.parse(res);
        let f = r.result;

        // let g = JSON.parse(f.otp.raw);
        if (f) {
            this.otp = f;
            return;
        }
        this.otp = "";
        return;
    };
    request(obj) {
        let now = parseInt(new Date().getTime() / 1000);
        let ts = "" + now;
        let body = {
            "method": "query",
            "param": "appToken",
            "timestamp": ts,
            "from": obj.plugin,
            "to": "HiOfficeClient",
            "extAttribute": ""    // 鏈潵瑕佷娇鐢ㄧ殑瀛楁
        };
        body = JSON.stringify(body);
        let enCodeData = otpUtils.encrypt(obj.key, body);
        let url = "http://127.0.0.1:" + this._port2 + "/hioffice?from=" + obj.plugin;
        otpUtils.fetchWithResponseHeader(2000, url, "post", enCodeData, (res, textStatus, response) => {
            this.resolveOtp(res);
            let hiInfo = otpUtils.toBase64(response.getResponseHeader('X-Tenant') + "|" + this.os);
            this.genIamToken(hiInfo, this.otp)
            return true;
        }, (xhr, err) => {
            if (xhr.status !== 200) {
                if (this._port2 >= 8992) {
                    this.genIamToken('', '')
                    return;
                }

                console.log("鏃犳硶鑾峰彇鍒扮敤鎴锋牎楠岀爜锛�")
                this._port2 = this._port2 + 2;
                this.request(obj);
                return false;
            }
        })
    };

    getKey() {
        const obj = { key: '', plugin: this.pluginId };
        if (this.os === "win") {
            obj.key = "ac786093f6094ccc982adb134afd5320".substring(0, 16);
        } else if (this.os === "mac") {
            obj.key = "019f4f11e30b4bf89f2d602b79c37007".substring(0, 16);
        }
        this.request(obj);
    }

    genIamToken(hiInfo, otp) {
        var data = { 'otp': otp, 'hiInfo': hiInfo }
        var xhr = new XMLHttpRequest()
        xhr.open('post', window.location.protocol + '//' + window.location.host + '/d6614fd1187d469a/gen', true)
        xhr.setRequestHeader('Content-Type', 'application/json;charset=UTF-8')
        xhr.withCredentials = true
        xhr.send(JSON.stringify(data))
    }
}

